8	} from '../../src/server/state-machine/transitions.js';
9	import type { State, Event } from '../../src/server/state-machine/states.js';
10	
11	// ---------------------------------------------------------------------------
12	// Helpers
13	// ---------------------------------------------------------------------------
14	
15	const ALL_STATES: readonly State[] = [
16	  'pending', 'ready', 'bootstrapping', 'bootstrap_failed',
17	  'in_progress', 'awaiting_retry', 'rate_limited',
18	  'awaiting_user', 'blocked', 'complete', 'abandoned',
19	];
20	
21	const ALL_EVENTS: readonly Event[] = [
22	  'deps_satisfied', 'phase_start', 'phase_advance', 'stage_complete',
23	  'stage_approval_granted', 'pre_commands_ok', 'pre_command_failed',
24	  'session_spawned', 'session_ok', 'session_fail',
25	  'rate_limit_detected', 'rate_limit_window_elapsed',
26	  'post_command_ok', 'post_command_action',
27	  'validators_ok', 'validator_fail', 'diff_check_ok', 'diff_check_fail',
28	  'retry_budget_remaining', 'retries_exhausted', 'backoff_elapsed',
29	  'user_retry', 'user_block', 'user_unblock_with_notes', 'user_cancel',
30	  'bootstrap_ok', 'bootstrap_fail',
31	];
32	
33	const TERMINAL_STATES = new Set<State>(['complete', 'abandoned', 'bootstrap_failed']);
34	
35	// bootstrapping is NOT in TERMINAL_STATES but it also does not have a
36	// user_cancel row in state-machine-transitions.md (only bootstrap_failed does).
37	// This set tracks states where the table explicitly lists user_cancel.
38	const STATES_WITH_USER_CANCEL = new Set<State>([
39	  'pending', 'ready', 'in_progress', 'awaiting_retry',
40	  'rate_limited', 'awaiting_user', 'blocked', 'abandoned',
41	]);
42	
43	/** Collect all `to` values reachable from a TransitionResult. */
44	function allTargets(result: TransitionResult): State[] {
45	  if (result.kind === 'direct') return [result.to];
46	  return result.outcomes.map(o => o.to);
47	}
48	
49	// ---------------------------------------------------------------------------
50	// Structural completeness
51	// ---------------------------------------------------------------------------
52	
53	describe('TRANSITIONS structural completeness', () => {
54	  it('has an entry for every State (compile-time and runtime)', () => {
55	    for (const s of ALL_STATES) {
56	      expect(TRANSITIONS).toHaveProperty(s);
57	    }
58	  });
59	
60	  it('has exactly the 11 defined States as keys — no extras', () => {
61	    const keys = Object.keys(TRANSITIONS) as State[];
62	    expect(keys.sort()).toEqual([...ALL_STATES].sort());
63	  });
64	
65	  it('every to-state in every result is a valid State', () => {
66	    const stateSet = new Set<string>(ALL_STATES);
67	    for (const s of ALL_STATES) {
68	      const row = TRANSITIONS[s];
69	      for (const e of ALL_EVENTS) {
70	        const result = row[e];
71	        if (result === undefined) continue;
72	        for (const target of allTargets(result)) {
73	          expect(stateSet).toContain(target);
74	        }
75	      }
76	    }
77	  });
78	
79	  it('all transition outcomes have non-empty guard when kind=conditional', () => {
80	    for (const s of ALL_STATES) {
81	      const row = TRANSITIONS[s];
82	      for (const e of ALL_EVENTS) {
83	        const result = row[e];
84	        if (result?.kind !== 'conditional') continue;
85	        for (const outcome of result.outcomes) {
86	          expect(outcome.guard.length).toBeGreaterThan(0);
87	        }
88	      }
89	    }
90	  });
91	});
92	
93	// ---------------------------------------------------------------------------
94	// transition() pure lookup contract
95	// ---------------------------------------------------------------------------
96	
97	describe('transition() pure lookup', () => {
98	  it('returns undefined for a pair not listed in the table', () => {
99	    // pending + bootstrap_ok is not a valid pair
100	    expect(transition('pending', 'bootstrap_ok')).toBeUndefined();
101	    // pending + session_fail is not a valid pair
102	    expect(transition('pending', 'session_fail')).toBeUndefined();
103	    // complete + user_cancel is not listed
104	    expect(transition('complete', 'user_cancel')).toBeUndefined();
105	    // complete + session_ok is not listed
106	    expect(transition('complete', 'session_ok')).toBeUndefined();
107	  });
108	
109	  it('returns the same reference on repeated calls (pure / no mutation)', () => {
110	    const r1 = transition('pending', 'deps_satisfied');
111	    const r2 = transition('pending', 'deps_satisfied');
112	    expect(r1).toBe(r2);
113	  });
114	
115	  it('does not throw for any (state, event) combination', () => {
116	    for (const s of ALL_STATES) {
117	      for (const e of ALL_EVENTS) {
118	        expect(() => transition(s, e)).not.toThrow();
119	      }
120	    }
121	  });
122	});
123	
124	// ---------------------------------------------------------------------------
125	// Specific transition spot-checks
126	// ---------------------------------------------------------------------------
127	
128	describe('pending transitions', () => {
