135	
136	  it('user_cancel → abandoned directly', () => {
137	    const r = transition('pending', 'user_cancel') as DirectTransitionResult;
138	    expect(r.kind).toBe('direct');
139	    expect(r.to).toBe('abandoned');
140	  });
141	});
142	
143	describe('ready transitions', () => {
144	  it('phase_start → conditional with bootstrapping and in_progress options', () => {
145	    const r = transition('ready', 'phase_start') as ConditionalTransitionResult;
146	    expect(r.kind).toBe('conditional');
147	    const targets = r.outcomes.map(o => o.to);
148	    expect(targets).toContain('bootstrapping');
149	    expect(targets).toContain('in_progress');
150	  });
151	
152	  it('user_cancel → abandoned', () => {
153	    const r = transition('ready', 'user_cancel') as DirectTransitionResult;
154	    expect(r.to).toBe('abandoned');
155	  });
156	});
157	
158	describe('bootstrapping transitions', () => {
159	  it('bootstrap_ok → in_progress', () => {
160	    const r = transition('bootstrapping', 'bootstrap_ok') as DirectTransitionResult;
161	    expect(r.kind).toBe('direct');
162	    expect(r.to).toBe('in_progress');
163	  });
164	
165	  it('bootstrap_fail → bootstrap_failed', () => {
166	    const r = transition('bootstrapping', 'bootstrap_fail') as DirectTransitionResult;
167	    expect(r.kind).toBe('direct');
