174	    // Every event except user_retry and user_cancel returns undefined
175	    const defined = new Set<Event>(['user_retry', 'user_cancel']);
176	    for (const e of ALL_EVENTS) {
177	      const r = transition('bootstrap_failed', e);
178	      if (defined.has(e)) {
179	        expect(r).toBeDefined();
